import React from "react";
import './Welcome.css';

function Welcome (props) {
    function handleUsernameChange (event) {
        console.log(event.target.username)
    }
    function handlePasswordChange (event) {
        console.log(event.target.password)
    }
    return  (
    <div class = 'title'>
        <h1>Welcome to Productiv!</h1>
    <form class = 'location-form'>
        <div>
        <label for="username"> Username </label>
        <input type="text" id="username" name="username" value = {props.username} onChange = {handleUsernameChange}></input>
        </div>
        <div>
        <label for="password"> Password </label>
        <input type="password" id="password" name="password" value = {props.password} onChange = {handlePasswordChange}></input>
        </div>
        <div>
        <input type="submit" value= "Log in" ></input>
        </div>
        <div>
        <input type="submit" value= "Sign up"></input>
        </div>
    </form>
    </div>
    )
}

export default Welcome;
